import anthropic

client = anthropic.Anthropic()

# Step functions — each has a single, fixed purpose
def step_reformulate_query(user_question: str) -> str:
    """LLM step: rewrite the question as a search query."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=64,
        messages=[{
            "role": "user",
            "content": f"Rewrite as a web search query (one line only): {user_question}"
        }]
    )
    return resp.content[0].text.strip()

def step_search(query: str) -> list[str]:
    """Tool step: run the search. (Stub; replace with real API.)"""
    return [
        f"Result 1 for '{query}': ...",
        f"Result 2 for '{query}': ...",
    ]

def step_synthesize(question: str, results: list[str]) -> str:
    """LLM step: synthesize search results into an answer."""
    context = "\n".join(results)
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        messages=[{
            "role": "user",
            "content": f"Question: {question}\n\nSources:\n{context}\n\nAnswer concisely:"
        }]
    )
    return resp.content[0].text

# Workflow orchestrator — step order is FIXED in code
def run_workflow(user_question: str) -> str:
    query = step_reformulate_query(user_question)   # always step 1
    results = step_search(query)                    # always step 2
    answer = step_synthesize(user_question, results) # always step 3
    return answer

print(run_workflow("What is the current Python version?"))

import json
import anthropic

client = anthropic.Anthropic()

tools = [
    {
        "name": "search",
        "description": "Search the web and return a list of snippets.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "fetch_page",
        "description": "Fetch the full text of a URL.",
        "input_schema": {
            "type": "object",
            "properties": {"url": {"type": "string"}},
            "required": ["url"],
        },
    },
]

def search(query: str) -> list:
    return [f"Snippet for '{query}': Python 3.13 released Oct 2024."]

def fetch_page(url: str) -> str:
    return f"[page content from {url}]"

TOOL_MAP = {"search": search, "fetch_page": fetch_page}

# Agent loop — step order is decided by the MODEL at runtime
def run_agent(user_question: str, max_steps: int = 10) -> str:
    messages = [{"role": "user", "content": user_question}]
    for _ in range(max_steps):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if hasattr(b, "text"))
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                # Model decided to call this tool — not us
                result = TOOL_MAP[block.name](**block.input)
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })
        messages.append({"role": "user", "content": results})
    return "[max steps reached]"

# The model may call search once, or search then fetch_page, or just answer
# without any tool call — it decides at runtime
print(run_agent("What is the current Python version?"))

